def _normalize_endpoint(path: str) -> str:
    """
    Normalize URL paths to prevent high-cardinality labels.
    Maps paths like /users/12345 to /users/:id
    """
    parts = path.strip("/").split("/")
    normalized = []
    for part in parts:
        if part.isdigit():
            normalized.append(":id")
        elif _looks_like_uuid(part):
            normalized.append(":uuid")
        else:
            normalized.append(part)
    result = "/" + "/".join(normalized) if normalized else "/"
    return result


def _looks_like_uuid(s: str) -> bool:
    """Check if a string looks like a UUID."""
    import re

    return bool(re.match(r"^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", s, re.I))


def _classify_error(status_code: int) -> str:
    """Classify HTTP errors into categories."""
    if status_code == 400:
        return "bad_request"
    elif status_code == 401:
        return "unauthorized"
    elif status_code == 403:
        return "forbidden"
    elif status_code == 404:
        return "not_found"
    elif status_code == 429:
        return "rate_limited"
    elif 400 <= status_code < 500:
        return "client_error"
    elif 500 <= status_code < 600:
        return "server_error"
    return "unknown"


